INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (1,'是 өгүүлбэр','是 sentence','是','「是」нь "юм", "мөн" гэсэн утгатай. Нэр үгийг нэр үгтэй холбоно.','Subject + 是 + Noun','[{"zh": "我是学生。", "pinyin": "Wǒ shì xuésheng.", "mn": "Би оюутан."}, {"zh": "她是老师。", "pinyin": "Tā shì lǎoshī.", "mn": "Тэр багш."}]',1,1);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (2,'不 үгүйсгэх','不 negation','不','「不」нь одоогийн болон ирээдүйн үйлдлийг үгүйсгэнэ.','Subject + 不 + Verb/Adj','[{"zh": "我不去。", "pinyin": "Wǒ bú qù.", "mn": "Би явахгүй."}, {"zh": "他不是学生。", "pinyin": "Tā bú shì xuésheng.", "mn": "Тэр оюутан биш."}]',1,2);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (3,'吗 асуулт','吗 question','吗','「吗」-г өгүүлбэрийн төгсгөлд нэмж тийм/үгүй асуулт болгоно.','Statement + 吗？','[{"zh": "你好吗？", "pinyin": "Nǐ hǎo ma?", "mn": "Чи сайн уу?"}, {"zh": "他是学生吗？", "pinyin": "Tā shì xuésheng ma?", "mn": "Тэр оюутан уу?"}]',1,3);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (4,'的 эзэмшил','的 possession','的','「的」нь эзэмшлийг илэрхийлнэ. Монгол хэлний "-ийн/-ын" гэсэн утгатай.','Possessor + 的 + Noun','[{"zh": "我的书", "pinyin": "Wǒ de shū", "mn": "Миний ном"}, {"zh": "她的老师", "pinyin": "Tā de lǎoshī", "mn": "Түүний багш"}]',1,4);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (5,'了 дууссан үйлдэл','了 completion','了','「了」нь үйлдэл дууссаныг илэрхийлнэ.','Verb + 了','[{"zh": "我买了苹果。", "pinyin": "Wǒ mǎi le píngguǒ.", "mn": "Би алим авлаа."}, {"zh": "他来了。", "pinyin": "Tā lái le.", "mn": "Тэр ирлээ."}]',1,5);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (6,'在 байршил','在 location','在','「在」нь хаана байгааг илэрхийлнэ.','Subject + 在 + Place','[{"zh": "我在家。", "pinyin": "Wǒ zài jiā.", "mn": "Би гэртээ байна."}, {"zh": "他在学校。", "pinyin": "Tā zài xuéxiào.", "mn": "Тэр сургуульд байна."}]',1,6);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (7,'在...呢 үргэлжилж буй','Progressive action','在...呢','「在...呢」нь яг одоо хийж байгаа үйлдлийг илэрхийлнэ.','Subject + 在 + Verb + 呢','[{"zh": "我在看书呢。", "pinyin": "Wǒ zài kàn shū ne.", "mn": "Би ном уншиж байна."}, {"zh": "他在吃饭呢。", "pinyin": "Tā zài chīfàn ne.", "mn": "Тэр хоол идэж байна."}]',1,7);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (8,'有 байгаа','有 existence','有','「有」нь "байна, бий" гэсэн утгатай.','Subject + 有 + Object','[{"zh": "我有一本书。", "pinyin": "Wǒ yǒu yì běn shū.", "mn": "Надад нэг ном байна."}, {"zh": "这儿有人。", "pinyin": "Zhèr yǒu rén.", "mn": "Энд хүн байна."}]',1,8);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (9,'没有 байхгүй','没有 negation','没/没有','「没有」нь 有-г үгүйсгэнэ. Мөн өнгөрсөн үйлдлийг 没-ээр үгүйсгэнэ.','Subject + 没有 + Noun','[{"zh": "我没有钱。", "pinyin": "Wǒ méiyǒu qián.", "mn": "Надад мөнгө байхгүй."}, {"zh": "他没去。", "pinyin": "Tā méi qù.", "mn": "Тэр яваагүй."}]',1,9);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (10,'Тоолох үг','Measure words','个/本/杯','Хятад хэлэнд тоо + тоолох үг + нэр үг гэсэн дарааллаар хэлнэ.','Number + MW + Noun','[{"zh": "一个人", "pinyin": "yí gè rén", "mn": "нэг хүн"}, {"zh": "三本书", "pinyin": "sān běn shū", "mn": "гурван ном"}, {"zh": "两杯茶", "pinyin": "liǎng bēi chá", "mn": "хоёр аяга цай"}]',1,10);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (11,'想 хүсэл','想 desire','想','「想」нь "~маар байна" гэсэн утгатай.','Subject + 想 + Verb','[{"zh": "我想喝茶。", "pinyin": "Wǒ xiǎng hē chá.", "mn": "Би цай уумаар байна."}, {"zh": "你想吃什么？", "pinyin": "Nǐ xiǎng chī shénme?", "mn": "Чи юу идмээр байна?"}]',1,11);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (12,'能/会 чадвар','能/会 ability','能/会','「会」суралцсан чадвар, 「能」боломж/зөвшөөрлийг илэрхийлнэ.','Subject + 能/会 + Verb','[{"zh": "我会说汉语。", "pinyin": "Wǒ huì shuō Hànyǔ.", "mn": "Би хятадаар ярьж чаддаг."}, {"zh": "你能来吗？", "pinyin": "Nǐ néng lái ma?", "mn": "Чи ирж чадах уу?"}]',1,12);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (13,'很/太 зэрэг','很/太 degree','很/太','「很」= маш, 「太...了」= хэтэрхий.','Subject + 很/太 + Adj','[{"zh": "我很好。", "pinyin": "Wǒ hěn hǎo.", "mn": "Би маш сайн."}, {"zh": "太好了！", "pinyin": "Tài hǎo le!", "mn": "Маш сайн!"}]',1,13);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (14,'也/都 дагавар','也/都 adverbs','也/都','「也」= бас/мөн, 「都」= бүгд.','Subject + 也/都 + Verb','[{"zh": "我也去。", "pinyin": "Wǒ yě qù.", "mn": "Би бас явна."}, {"zh": "我们都是学生。", "pinyin": "Wǒmen dōu shì xuésheng.", "mn": "Бид бүгд оюутан."}]',1,14);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (15,'Асуух үгс','Question words','什么/谁/哪/几','Асуух үгийг хариулт байх ёстой байрлалд тавина.','Question word in answer position','[{"zh": "你叫什么？", "pinyin": "Nǐ jiào shénme?", "mn": "Чиний нэр юу?"}, {"zh": "谁是老师？", "pinyin": "Shéi shì lǎoshī?", "mn": "Хэн нь багш вэ?"}]',1,15);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (16,'呢 давтах асуулт','呢 follow-up','呢','「呢」-ээр "Та юу?" гэж давтах асуулт тавина.','Noun/Pronoun + 呢？','[{"zh": "我很好，你呢？", "pinyin": "Wǒ hěn hǎo, nǐ ne?", "mn": "Би сайн, чи юу?"}, {"zh": "他去北京，你呢？", "pinyin": "Tā qù Běijīng, nǐ ne?", "mn": "Тэр Бээжинд явна, чи юу?"}]',1,16);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (17,'Цаг хугацааны байрлал','Time placement','Time before verb','Хятад хэлэнд цаг хугацаа үйл үгийн ӨМНӨ байрлана.','Subject + Time + Verb','[{"zh": "我明天去。", "pinyin": "Wǒ míngtiān qù.", "mn": "Би маргааш явна."}, {"zh": "他今天不来。", "pinyin": "Tā jīntiān bù lái.", "mn": "Тэр өнөөдөр ирэхгүй."}]',1,17);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (18,'SVO бүтэц','Word order','SVO','Хятад хэлний үндсэн бүтэц: Эзэн + Цаг + Байршил + Үйл + Тусагдахуун.','Subject + Time + Place + Verb + Object','[{"zh": "我下午在学校学习。", "pinyin": "Wǒ xiàwǔ zài xuéxiào xuéxí.", "mn": "Би үдээс хойш сургуульд суралцна."}, {"zh": "他每天喝茶。", "pinyin": "Tā měitiān hē chá.", "mn": "Тэр өдөр бүр цай ууна."}]',1,18);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (19,'喜欢 + Verb','喜欢 + Verb','喜欢','「喜欢」нь дуртай зүйлээ илэрхийлнэ.','Subject + 喜欢 + Verb/Noun','[{"zh": "我喜欢看书。", "pinyin": "Wǒ xǐhuan kàn shū.", "mn": "Би ном уншихыг дуртай."}, {"zh": "她喜欢中国菜。", "pinyin": "Tā xǐhuan Zhōngguó cài.", "mn": "Тэр хятад хоолонд дуртай."}]',1,19);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (20,'请 эелдэг хүсэлт','请 polite','请','「请」нь эелдэг хүсэлт гаргахад хэрэглэнэ.','请 + Verb','[{"zh": "请坐。", "pinyin": "Qǐng zuò.", "mn": "Суугаарай."}, {"zh": "请说。", "pinyin": "Qǐng shuō.", "mn": "Хэлнэ үү."}]',1,20);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (21,'Уучлал','Apology','对不起/没关系','「对不起」= уучлаарай, 「没关系」= зүгээр дээ.','对不起 → 没关系','[{"zh": "对不起！", "pinyin": "Duìbuqǐ!", "mn": "Уучлаарай!"}, {"zh": "没关系。", "pinyin": "Méi guānxi.", "mn": "Зүгээр дээ."}]',1,21);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (22,'Тоо 1-99','Numbers 1-99','Numbers','11=十一, 20=二十, 35=三十五 гэх мэтчилэн тоолно.','十位 + 个位','[{"zh": "十一", "pinyin": "shíyī", "mn": "арван нэг"}, {"zh": "二十", "pinyin": "èrshí", "mn": "хорь"}, {"zh": "三十五", "pinyin": "sānshíwǔ", "mn": "гучин тав"}]',1,22);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (23,'Огноо, цаг','Date & time','年月日/点分','2024年1月1日 = 2024 оны 1-р сарын 1. Цаг: 三点半 = 3:30.','Year+年 Month+月 Day+日','[{"zh": "今天一月五号。", "pinyin": "Jīntiān yī yuè wǔ hào.", "mn": "Өнөөдөр 1-р сарын 5."}, {"zh": "现在三点。", "pinyin": "Xiànzài sān diǎn.", "mn": "Одоо 3 цаг."}]',1,23);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (24,'怎么 хэрхэн','怎么 how','怎么','「怎么」нь "хэрхэн/яаж" гэсэн утгатай.','怎么 + Verb?','[{"zh": "怎么去？", "pinyin": "Zěnme qù?", "mn": "Яаж явах вэ?"}, {"zh": "你怎么来的？", "pinyin": "Nǐ zěnme lái de?", "mn": "Чи яаж ирсэн бэ?"}]',1,24);
INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num) VALUES (25,'是...的 онцлох','是...的 emphasis','是...的','「是...的」нь хэзээ, хаана, яаж гэдгийг онцолно.','是 + Detail + 的','[{"zh": "我是坐飞机来的。", "pinyin": "Wǒ shì zuò fēijī lái de.", "mn": "Би онгоцоор ирсэн юм."}, {"zh": "他是昨天来的。", "pinyin": "Tā shì zuótiān lái de.", "mn": "Тэр өчигдөр ирсэн юм."}]',1,25);
