INSERT INTO grammar_exercises (id,grammar_lesson_id,exercise_type,question_zh,correct_answer,options,explanation_mn,order_num) VALUES (25,9,'fill_blank','我___钱。','没有','["没有","不有","没是","不在"]','有-г үгүйсгэхдээ 没有 хэрэглэнэ',1);
